runtime = AgentRuntime(config_path="agent.yaml")
step_generator = runtime.execute_iterative(prompt="Calculate sales tax for $1500")

for step in step_generator:
    print(f"Step Type: {step.type}")
    if step.type == "tool_call":
        print(f"Invoking Tool: {step.tool_name} with {step.args}")
    elif step.type == "model_thinking":
        print("Agent is processing...")
